import{_ as s,o as e,c as n,a}from"./app.e18a9c6c.js";const D=JSON.parse('{"title":"Iterators","description":"","frontmatter":{},"headers":[],"relativePath":"guide/iterators.md"}'),o={name:"guide/iterators.md"},t=a(`<h1 id="iterators" tabindex="-1">Iterators <a class="header-anchor" href="#iterators" aria-hidden="true">#</a></h1><p><code>vue-vnode-utils</code> provides several iterator functions that can be used to walk slot VNodes <em>without</em> modifying them. They are roughly equivalent to the iterator methods found on arrays:</p><table><thead><tr><th>Array</th><th>vue-vnode-utils</th></tr></thead><tbody><tr><td>forEach()</td><td>eachChild()</td></tr><tr><td>every()</td><td>everyChild()</td></tr><tr><td>find()</td><td>findChild()</td></tr><tr><td>some()</td><td>someChild()</td></tr></tbody></table><p>Each of the iterators takes three arguments. The first is the array of children to iterate, which is usually created by calling a slot function. The second is a callback function that will be passed the top-level VNodes in the order they appear.</p><div class="language-js"><button class="copy"></button><span class="lang">js</span><pre><code><span class="line"><span style="color:#89DDFF;">import</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">eachChild</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">from</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">@skirtle/vue-vnode-utils</span><span style="color:#89DDFF;">&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;">// Inside a render function</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> children </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> slots</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">default</span><span style="color:#89DDFF;">?.</span><span style="color:#A6ACCD;">() </span><span style="color:#89DDFF;">??</span><span style="color:#A6ACCD;"> []</span></span>
<span class="line"></span>
<span class="line"><span style="color:#82AAFF;">eachChild</span><span style="color:#A6ACCD;">(children</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">vnode</span><span style="color:#89DDFF;">)</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">=&gt;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#A6ACCD;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#A6ACCD;">vnode</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">type</span><span style="color:#F07178;">)</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"></span></code></pre></div><p>Just like the array methods...</p><ul><li><code>eachChild()</code> will ignore the value returned by the callback. When iteration is complete it returns <code>undefined</code>.</li><li><code>everyChild()</code> will stop iterating if the callback returns a falsy value. When iteration is complete it returns either <code>true</code> or <code>false</code>.</li><li><code>findChild()</code> will stop iterating if the callback returns a truthy value and return the corresponding VNode.</li><li><code>someChild()</code> will stop iterating if the callback returns a truthy value. When iteration is complete it returns either <code>true</code> or <code>false</code>.</li></ul><p>The array of children does not necessarily need to contain fully instantiated VNodes. For example, text nodes can be represented as just strings and fragments can be arrays. This is consistent with how Vue handles the children passed to <code>h</code>, and how it handles values returned from render functions or within slot functions. If you obtained your array of children by calling a slot function then Vue will have already promoted the children to full VNodes, but the iterators don&#39;t require that.</p><p>The iterator callback will be passed a fully instantiated VNode, even if the original child array contained some other representation of the child. This is a design choice. <code>vue-vnode-utils</code> aims to remove the burden of worrying about the various edge cases, but here we have to pick between two different edge cases. The callbacks only need to worry about handling full VNodes, but the tradeoff is that that exact VNode may not be in the original array. In practice, this should only affect text and comment nodes, and only in cases where they haven&#39;t come from a slot function.</p><p>Fragment nodes are never passed to the iterator callback. Instead, the iterator will iterate through the children of the fragment. The iterators do not walk the children of any other node type, just fragments. They are only attempting to iterate what would generally be considered the &#39;top-level&#39; VNodes.</p><p>The optional third argument for each iterator is an object containing <a href="/vue-vnode-utils/api.html#iterationoptions">iteration options</a>. The iterators will usually pass all node types to the callback, but the options can be used to restrict iteration to specific types of node. The available node types are <code>component</code>, <code>element</code>, <code>text</code>, <code>comment</code> and <code>static</code>.</p><p>So if we only want to iterate over <code>text</code> nodes we can pass <code>{ text: true }</code> as the third argument.</p><p>There are constants available for the most common combinations: <code>ALL_VNODES</code>, <code>SKIP_COMMENTS</code> and <code>COMPONENTS_AND_ELEMENTS</code>. The iterators all default to <code>ALL_VNODES</code>.</p><p>The following example defines a functional component that counts the number of children in its slot. The count is displayed above the list and the wrapper <code>&lt;ul&gt;</code> element is not rendered if there are no children:</p><div class="language-js"><button class="copy"></button><span class="lang">js</span><pre><code><span class="line"><span style="color:#89DDFF;">import</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">h</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">from</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">vue</span><span style="color:#89DDFF;">&#39;</span></span>
<span class="line"><span style="color:#89DDFF;">import</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">eachChild</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">SKIP_COMMENTS</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">from</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">@skirtle/vue-vnode-utils</span><span style="color:#89DDFF;">&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">function</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">ChildComponent</span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">_</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#A6ACCD;"> </span><span style="color:#A6ACCD;">slots</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">})</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#C792EA;">const</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">children</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">=</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">slots</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">default</span><span style="color:#89DDFF;">?.</span><span style="color:#F07178;">() </span><span style="color:#89DDFF;">??</span><span style="color:#F07178;"> []</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#C792EA;">let</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">count</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">=</span><span style="color:#F07178;"> </span><span style="color:#F78C6C;">0</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#82AAFF;">eachChild</span><span style="color:#F07178;">(</span><span style="color:#A6ACCD;">children</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">()</span><span style="color:#F07178;"> </span><span style="color:#C792EA;">=&gt;</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">count</span><span style="color:#89DDFF;">++,</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">SKIP_COMMENTS</span><span style="color:#F07178;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#89DDFF;">return</span><span style="color:#F07178;"> </span><span style="color:#82AAFF;">h</span><span style="color:#F07178;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">div</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> [</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#82AAFF;">h</span><span style="color:#F07178;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">div</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">\`</span><span style="color:#C3E88D;">Child count: </span><span style="color:#89DDFF;">\${</span><span style="color:#A6ACCD;">count</span><span style="color:#89DDFF;">}\`</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#A6ACCD;">count</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">?</span><span style="color:#F07178;"> </span><span style="color:#82AAFF;">h</span><span style="color:#F07178;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">ul</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">children</span><span style="color:#F07178;">) </span><span style="color:#89DDFF;">:</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">null</span></span>
<span class="line"><span style="color:#F07178;">  ])</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><p>See it on the SFC Playground: <a href="https://sfc.vuejs.org/#" target="_blank" rel="noreferrer">Composition API</a> | <a href="https://sfc.vuejs.org/#" target="_blank" rel="noreferrer">Options API</a></p><p>The example uses <code>SKIP_COMMENTS</code> to skip over the comment nodes created by the falsy <code>v-if</code> conditions.</p><p>While this example needs to display the count, a more common scenario involves only needing to know whether the count is 0. The <a href="/vue-vnode-utils/api.html#isempty"><code>isEmpty()</code></a> helper can be used in that case.</p><p>It is worth noting that the count here is just a count of the VNodes. It is not necessarily an accurate count of the number of <code>&lt;li&gt;</code> elements. If any of the children had been a component it would have added 1 to the count, even though a component wouldn&#39;t necessarily render exactly one <code>&lt;li&gt;</code> element.</p>`,19),l=[t];function p(r,c,i,d,y,h){return e(),n("div",null,l)}const A=s(o,[["render",p]]);export{D as __pageData,A as default};
